     6→pub fn command_available(name: &str) -> bool {
     7→    // Try system PATH first
     8→    if StdCommand::new(name)
     9→        .arg("--version")
    10→        .output()
    11→        .map(|o| o.status.success())
    12→        .unwrap_or(false)
    13→    {
    14→        return true;
    15→    }
    16→    // Try well-known user-local paths
    17→    let home = std::env::var("HOME").unwrap_or_default();
    18→    for dir in [
    19→        format!("{home}/.local/bin"),
    20→        format!("{home}/.cargo/bin"),
    21→        "/opt/homebrew/bin".to_string(),
    22→    ] {
    23→        let full = format!("{dir}/{name}");
    24→        if StdCommand::new(&full)
    25→            .arg("--version")
    26→            .output()
    27→            .map(|o| o.status.success())
    28→            .unwrap_or(false)
    29→        {
    30→            return true;
    31→        }
    32→    }
    33→    false
    34→}
