    36→pub fn cmd_doctor(cards_root: &Path) -> anyhow::Result<()> {
    37→    println!("bop doctor");
    38→
    39→    // ── core tools ──────────────────────────────────────────────────────────
    40→    println!("\n── tools ──");
    41→    let checks = [
    42→        ("git", command_available("git")),
    43→        ("gt", command_available("gt")),
    44→        ("jj", command_available("jj")),
    45→        ("gh", command_available("gh")),
    46→        ("nu", command_available("nu")),
    47→        ("zellij", command_available("zellij")),
    48→    ];
    49→
    50→    let mut failed = 0;
    51→    for (name, ok) in checks {
    52→        if ok {
    53→            println!("ok\t{}", name);
    54→        } else {
    55→            println!("missing\t{}", name);
    56→            failed += 1;
    57→        }
    58→    }
    59→
    60→    // ── zellij plugin ──────────────────────────────────────────────────────
    61→    let home = std::env::var("HOME").unwrap_or_default();
    62→    let plugin_path = Path::new(&home).join(".config/zellij/plugins/bop.wasm");
    63→    if plugin_path.exists() {
    64→        println!("ok\tzellij plugin ({})", plugin_path.display());
    65→    } else {
    66→        println!("missing\tzellij plugin (run `bop factory install`)");
    67→    }
    68→
    69→    // ── adapters ────────────────────────────────────────────────────────────
    70→    println!("\n── adapters ──");
    71→    let adapters_dir = cards_root.parent().unwrap_or(cards_root).join("adapters");
    72→
    73→    // Map adapter name → CLI binary it requires
    74→    let adapter_cli_map: &[(&str, &str)] = &[
    75→        ("claude", "claude"),
    76→        ("codex", "codex"),
    77→        ("ollama-local", "ollama"),
    78→        ("goose", "goose"),
    79→        ("aider", "aider"),
    80→        ("opencode", "opencode"),
    81→        ("mock", "true"), // mock always works
    82→    ];
    83→
    84→    if adapters_dir.is_dir() {
    85→        for (adapter, cli) in adapter_cli_map {
    86→            let script = adapters_dir.join(format!("{}.nu", adapter));
    87→            if !script.exists() {
    88→                continue; // adapter not installed, skip
    89→            }
    90→            let cli_ok = command_available(cli);
    91→            if cli_ok {
    92→                println!("ok\t{}\t({})", adapter, cli);
    93→            } else {
    94→                println!("missing\t{}\t({} not found)", adapter, cli);
    95→                // Adapter missing is a warning, not a hard failure —
    96→                // the system works with any subset of adapters
    97→            }
    98→        }
    99→    } else {
   100→        println!("warn\tadapters/ directory not found");
   101→    }
   102→
   103→    // ── cards layout ────────────────────────────────────────────────────────
   104→    println!("\n── cards ──");
   105→    let policy = cards_root.join("policy.toml");
   106→    if policy.exists() {
   107→        println!("ok\t{}", policy.display());
   108→    } else {
   109→        println!("missing\t{}", policy.display());
   110→        failed += 1;
   111→    }
   112→
   113→    let system_ctx = cards_root.join("system_context.md");
   114→    if system_ctx.exists() {
   115→        println!("ok\tsystem_context.md");
   116→    } else {
   117→        println!("missing\tsystem_context.md");
   118→    }
   119→
   120→    let stages_dir = cards_root.join("stages");
   121→    if stages_dir.is_dir() {
   122→        let n_stages = fs::read_dir(&stages_dir)
   123→            .map(|rd| {
   124→                rd.filter(|e| {
   125→                    e.as_ref()
   126→                        .map(|e| e.path().extension().map(|x| x == "md").unwrap_or(false))
   127→                        .unwrap_or(false)
   128→                })
   129→                .count()
   130→            })
   131→            .unwrap_or(0);
   132→        println!("ok\tstages/ ({} files)", n_stages);
   133→    } else {
   134→        println!("missing\tstages/");
   135→    }
   136→
   137→    let templates_dir = cards_root.join("templates");
   138→    if templates_dir.is_dir() {
   139→        let n_templates = fs::read_dir(&templates_dir)
   140→            .map(|rd| {
   141→                rd.filter(|e| {
   142→                    e.as_ref()
   143→                        .map(|e| e.path().extension().map(|x| x == "bop").unwrap_or(false))
   144→                        .unwrap_or(false)
   145→                })
   146→                .count()
   147→            })
   148→            .unwrap_or(0);
   149→        println!("ok\ttemplates/ ({} templates)", n_templates);
   150→    } else {
   151→        println!("missing\ttemplates/");
   152→    }
   153→
   154→    // ── acceptance criteria lint ────────────────────────────────────────────
   155→    println!("\n── acceptance criteria ──");
   156→    let pending_dir = cards_root.join("pending");
   157→    if pending_dir.is_dir() {
   158→        let mut any_cards = false;
   159→        if let Ok(entries) = fs::read_dir(&pending_dir) {
   160→            for entry in entries.flatten() {
   161→                let card_dir = entry.path();
   162→                if card_dir.extension().map(|e| e == "bop").unwrap_or(false) && card_dir.is_dir() {
   163→                    let meta_path = card_dir.join("meta.json");
   164→                    let Ok(meta) = bop_core::read_meta(&card_dir) else {
   165→                        continue;
   166→                    };
   167→                    if meta.acceptance_criteria.is_empty() {
   168→                        continue;
   169→                    }
   170→                    any_cards = true;
   171→                    let card_id = card_dir.file_stem().and_then(|s| s.to_str()).unwrap_or("?");
   172→                    let _ = meta_path; // read above
   173→                    let is_git_mode = matches!(meta.vcs_engine, Some(CoreVcsEngine::GitGt));
   174→                    let mut issues: Vec<String> = Vec::new();
   175→                    for (idx, cmd) in meta.acceptance_criteria.iter().enumerate() {
   176→                        // 1. Absolute paths
   177→                        if cmd.contains("/Users/") || cmd.contains("/home/") {
   178→                            issues.push(format!(
   179→                                "criteria[{idx}] — absolute path (non-portable): {cmd}"
   180→                            ));
   181→                        }
   182→                        // 2. Missing binary (first token)
   183→                        let binary = cmd.split_whitespace().next().unwrap_or("");
   184→                        if !binary.is_empty() && !command_available(binary) {
   185→                            issues.push(format!("criteria[{idx}] — binary not found: {binary}"));
   186→                        }
   187→                        // 3. jj commands in git mode
   188→                        if is_git_mode {
   189→                            let first = cmd.split_whitespace().next().unwrap_or("");
   190→                            if first == "jj" {
   191→                                issues.push(format!(
   192→                                    "criteria[{idx}] — jj command but vcs_engine is git_gt: {cmd}"
   193→                                ));
   194→                            }
   195→                        }
   196→                    }
   197→                    if issues.is_empty() {
   198→                        println!(
   199→                            "✓ {}: {} criteria OK",
   200→                            card_id,
   201→                            meta.acceptance_criteria.len()
   202→                        );
   203→                    } else {
   204→                        for issue in &issues {
   205→                            println!("✗ {card_id}: {issue}");
   206→                        }
   207→                    }
   208→                }
   209→            }
   210→        }
   211→        if !any_cards {
   212→            println!("ok\tno pending cards with acceptance criteria");
   213→        }
   214→    } else {
   215→        println!("ok\tno pending/ directory");
   216→    }
   217→
   218→    if failed > 0 {
   219→        anyhow::bail!("doctor found {} issue(s)", failed);
   220→    }
   221→    Ok(())
   222→}
