    10→pub fn ensure_cards_layout(root: &Path) -> anyhow::Result<()> {
    11→    for dir in [
    12→        "templates",
    13→        "drafts",
    14→        "pending",
    15→        "running",
    16→        "done",
    17→        "merged",
    18→        "failed",
    19→        "memory",
    20→    ] {
    21→        fs::create_dir_all(root.join(dir))?;
    22→    }
