#[test]
fn parse_valid_cards_config() {
    let json = r#"{"zellij_session": "bop"}"#;
    let cfg = parse_cards_config(json).unwrap();
    assert_eq!(cfg.zellij_session, Some("bop".to_string()));
}

#[test]
fn parse_empty_cards_config() {
